package com.pqc.core.controller;
import com.pqc.core.dto.*; import com.pqc.core.entity.*; import com.pqc.core.security.CurrentUser; import com.pqc.core.service.MarketingAdminService; import lombok.RequiredArgsConstructor; import org.springframework.data.domain.Page; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/v1/admin/marketing") @RequiredArgsConstructor public class MarketingAdminController {private final MarketingAdminService service;private final CurrentUser currentUser;
@GetMapping("/dashboard") public MarketingDashboardResponse dashboard(){return service.dashboard();}@GetMapping("/offers") public Page<OfferSummaryResponse> offers(@RequestParam(required=false)Boolean active,@RequestParam(required=false)DiscountType discountType,@RequestParam(required=false)String search,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return service.listOffers(active,discountType,search,page,size);}@PostMapping("/offers") public OfferDetailResponse createOffer(@RequestBody OfferCreateRequest r){return service.createOffer(r);}@GetMapping("/offers/{id}") public OfferDetailResponse offer(@PathVariable Long id){return service.getOffer(id);}@PatchMapping("/offers/{id}") public OfferDetailResponse updateOffer(@PathVariable Long id,@RequestBody OfferUpdateRequest r){return service.updateOffer(id,r);}@PatchMapping("/offers/{id}/activate") public OfferDetailResponse activateOffer(@PathVariable Long id){return service.setOfferActive(id,true);}@PatchMapping("/offers/{id}/deactivate") public OfferDetailResponse deactivateOffer(@PathVariable Long id){return service.setOfferActive(id,false);}
@GetMapping("/campaigns") public Page<CampaignSummaryResponse> campaigns(@RequestParam(required=false)CampaignStatus status,@RequestParam(required=false)CampaignType campaignType,@RequestParam(required=false)String search,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return service.listCampaigns(status,campaignType,search,page,size);}@PostMapping("/campaigns") public CampaignDetailResponse createCampaign(@RequestBody CampaignCreateRequest r){return service.createCampaign(r);}@GetMapping("/campaigns/{id}") public CampaignDetailResponse campaign(@PathVariable Long id){return service.getCampaign(id);}@PatchMapping("/campaigns/{id}/status") public CampaignDetailResponse campaignStatus(@PathVariable Long id,@RequestBody CampaignStatusUpdateRequest r){return service.updateCampaignStatus(id,r);}
@GetMapping("/banners") public List<BannerSummaryResponse> banners(){return service.listBanners();}@PostMapping("/banners") public BannerSummaryResponse createBanner(@RequestBody BannerCreateRequest r){return service.createBanner(r);}@PatchMapping("/banners/{id}") public BannerSummaryResponse updateBanner(@PathVariable Long id,@RequestBody BannerUpdateRequest r){return service.updateBanner(id,r);}@PatchMapping("/banners/{id}/activate") public BannerSummaryResponse activateBanner(@PathVariable Long id){return service.setBannerActive(id,true);}@PatchMapping("/banners/{id}/deactivate") public BannerSummaryResponse deactivateBanner(@PathVariable Long id){return service.setBannerActive(id,false);}
@GetMapping("/notifications") public List<MarketingNotificationResponse> notifications(){return service.listNotifications();}@PostMapping("/notifications/send") public MarketingNotificationResponse send(@RequestBody MarketingNotificationRequest r){return service.sendNotification(r,currentUser.require().getId());}@GetMapping("/segments") public List<UserSegmentResponse> segments(){return service.segments();}@GetMapping("/reports") public MarketingReportResponse reports(){return service.report();}}
